                "detailHtml": "<article>\r\n                <span class=\"pic\">\r\n                    <img src=\"https://github.com/kelvinlinkk/portfolio/raw/main/競賽/高一圖文創作.jpg\">\r\n                    <p><a href=\"https://github.com/kelvinlinkk/portfolio/raw/main/競賽/高一圖文創作.pdf\">相關資料下載</a></p>\r\n                </span>\r\n                <h2>競賽內容</h2>\r\n                <br />\r\n                <p>\r\n                    &emsp;&emsp;在這個比賽中，我們需要即興創作一首新詩，並畫上一張精美的圖片與內容題材相呼應。\r\n                </p>\r\n            </article>\r\n            <hr>\r\n\r\n            <article>\r\n                <span class=\"pic\">\r\n                    <iframe src=\"http://www.ytjh.ylc.edu.tw/news/1/2602\"></iframe>\r\n                    <p>學校官網</p>\r\n                </span>\r\n                <h2>心得感想</h2>\r\n                <br />\r\n                <p>\r\n                    &emsp;&emsp;在活動中，我們通過團隊合作，在有限的時間完成了要求，並創作出了一首新詩。\r\n                </p>\r\n            </article>\r\n            <hr>\r\n\r\n            <article>\r\n                <h2>作品</h2>\r\n                <br />\r\n                <p>\r\n                    &emsp;&emsp;<br><br>\r\n                </p>\r\n            </article>\r\n            ",
